import{_ as a,o as n,c as e,ag as i}from"./chunks/framework.D4O_uTxf.js";const u=JSON.parse('{"title":"ADR-001: Rust Crate Structure — Workspace with Focused Modules","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-001-rust-crate-structure.md","filePath":"adr/ADR-001-rust-crate-structure.md","lastUpdated":1771844172000}'),t={name:"adr/ADR-001-rust-crate-structure.md"};function l(p,s,o,r,c,h){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="adr-001-rust-crate-structure-—-workspace-with-focused-modules" tabindex="-1">ADR-001: Rust Crate Structure — Workspace with Focused Modules <a class="header-anchor" href="#adr-001-rust-crate-structure-—-workspace-with-focused-modules" aria-label="Permalink to &quot;ADR-001: Rust Crate Structure — Workspace with Focused Modules&quot;">​</a></h1><p><strong>Date:</strong> 2026-02-21</p><p><strong>Status:</strong> ACCEPTED</p><p><strong>Author:</strong> CIV Architecture Team</p><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The CIV city simulation engine requires modular architecture supporting multiple distinct simulation domains:</p><ul><li>Economy (ledger, market clearing)</li><li>Spatial representation (LOD, districts, actors)</li><li>Climate (energy accounting)</li><li>Institutions &amp; actors (lifecycle, state machines)</li><li>Geopolitics (conflict, diplomacy)</li><li>Social dynamics (ideology, health, insurgency)</li></ul><p>A monolithic crate would couple these domains unnecessarily. Separate crates enable:</p><ul><li>Independent testing and iteration</li><li>Clear boundary enforcement (via <code>tach.toml</code>)</li><li>Easier integration with Venture platform (each crate has well-defined API)</li><li>Parallel development across teams</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Organize CIV as a <strong>Rust workspace</strong> with the following focused crates:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>civ/</span></span>
<span class="line"><span>  Cargo.toml (workspace root)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  crates/</span></span>
<span class="line"><span>    engine/          # Core simulation loop (CIV-0001)</span></span>
<span class="line"><span>                     # - Tick-based state machine</span></span>
<span class="line"><span>                     # - Event ordering logic</span></span>
<span class="line"><span>                     # - Determinism/replay contract</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    economy/         # Economy module (CIV-0100)</span></span>
<span class="line"><span>                     # - Ledger, market clearing, transfers</span></span>
<span class="line"><span>                     # - Depends on: engine</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    spatial/         # Spatial &amp; LOD (CIV-0101)</span></span>
<span class="line"><span>                     # - District/agent representation</span></span>
<span class="line"><span>                     # - LOD transitions</span></span>
<span class="line"><span>                     # - Neighbor queries</span></span>
<span class="line"><span>                     # - Depends on: engine</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    climate/         # Climate module (CIV-0102)</span></span>
<span class="line"><span>                     # - Energy accounting, conservation equation</span></span>
<span class="line"><span>                     # - Weather events</span></span>
<span class="line"><span>                     # - Depends on: engine, economy (energy supply)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    actors/          # Institutions &amp; citizen lifecycle (CIV-0103)</span></span>
<span class="line"><span>                     # - Actor state machines</span></span>
<span class="line"><span>                     # - Institution formation/dissolution</span></span>
<span class="line"><span>                     # - Time-series metrics</span></span>
<span class="line"><span>                     # - Depends on: engine, economy, spatial</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    policy/          # Policy evaluation framework (CIV-0100, CIV-0104)</span></span>
<span class="line"><span>                     # - Policy.evaluate() interface</span></span>
<span class="line"><span>                     # - Constraint solver (minimal constraint set theorem)</span></span>
<span class="line"><span>                     # - Determinism validator</span></span>
<span class="line"><span>                     # - Depends on: engine, economy, actors</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    geo/             # Geopolitics (CIV-0105)</span></span>
<span class="line"><span>                     # - War, diplomacy, shadow networks</span></span>
<span class="line"><span>                     # - Conflict resolution</span></span>
<span class="line"><span>                     # - Depends on: engine, actors, spatial</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    social/          # Social dynamics (CIV-0106)</span></span>
<span class="line"><span>                     # - Ideology, health, insurgency</span></span>
<span class="line"><span>                     # - Cohesion metrics</span></span>
<span class="line"><span>                     # - Depends on: engine, actors, spatial</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    metrics/         # Observability (Venture integration)</span></span>
<span class="line"><span>                     # - Event recording</span></span>
<span class="line"><span>                     # - Time-series storage</span></span>
<span class="line"><span>                     # - Audit trail hooks</span></span>
<span class="line"><span>                     # - Depends on: engine, economy, actors, climate</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    server/          # HTTP/gRPC server (Venture integration)</span></span>
<span class="line"><span>                     # - EventEnvelopeV1 emission</span></span>
<span class="line"><span>                     # - Policy.evaluate tool endpoint</span></span>
<span class="line"><span>                     # - Artifact export pipeline</span></span>
<span class="line"><span>                     # - Depends on: (all modules above)</span></span></code></pre></div><h2 id="dependency-graph-enforced-via-tach-toml" tabindex="-1">Dependency Graph (Enforced via <code>tach.toml</code>) <a class="header-anchor" href="#dependency-graph-enforced-via-tach-toml" aria-label="Permalink to &quot;Dependency Graph (Enforced via \`tach.toml\`)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>server  ─────┬─ metrics</span></span>
<span class="line"><span>             ├─ economy  ─────┬─ engine</span></span>
<span class="line"><span>             ├─ climate  ─────┤─ economy</span></span>
<span class="line"><span>             ├─ actors   ─────┼─ spatial ─── engine</span></span>
<span class="line"><span>             ├─ geo      ─────┤─ policy</span></span>
<span class="line"><span>             ├─ social   ──────┴─ engine</span></span>
<span class="line"><span>             └─ policy</span></span>
<span class="line"><span></span></span>
<span class="line"><span>            (All non-root crates depend on engine)</span></span></code></pre></div><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ol><li><p><strong>Clear Separation of Concerns</strong></p><ul><li>Each crate has a single, well-defined responsibility</li><li>Easier to test and reason about in isolation</li><li>Matches spec organization (CIV-0100, CIV-0101, etc.)</li></ul></li><li><p><strong>Boundary Enforcement</strong></p><ul><li>Use <code>tach.toml</code> to enforce dependency graph</li><li>Prevents accidental coupling (e.g., economy should not depend on geo)</li><li>CI rejects violations</li></ul></li><li><p><strong>Parallel Development</strong></p><ul><li>Teams can work on crates independently</li><li>Reduced merge conflicts on shared files</li><li>Clear handoff points (crate APIs)</li></ul></li><li><p><strong>Venture Integration</strong></p><ul><li><code>server/</code> crate provides single integration point</li><li>EventEnvelopeV1, tool endpoints, artifact export all in one place</li><li>Easier to version and test Venture contracts</li></ul></li><li><p><strong>Performance &amp; Build Time</strong></p><ul><li>Only build changed crates in incremental builds</li><li>Team members can work on one domain without pulling all code</li></ul></li></ol><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Reduced cyclomatic complexity per crate</li><li>Clearer ownership and accountability</li><li>Easier to onboard new team members to specific domains</li><li>Boundary violations caught at compile time</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>More complex workspace management (multiple Cargo.tomls)</li><li>Cross-crate API changes require coordination</li><li>Workspace build is slower than monolithic initially (improves with incremental builds)</li><li>More CI/CD configuration</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><h3 id="a1-monolithic-crate" tabindex="-1">A1: Monolithic Crate <a class="header-anchor" href="#a1-monolithic-crate" aria-label="Permalink to &quot;A1: Monolithic Crate&quot;">​</a></h3><p><strong>Pros:</strong> Simpler build, shared internal state <strong>Cons:</strong> Tight coupling, hard to parallelize, cyclomatic complexity grows unbounded <strong>Rejected:</strong> Does not scale with 8 spec modules</p><h3 id="a2-separate-repos" tabindex="-1">A2: Separate Repos <a class="header-anchor" href="#a2-separate-repos" aria-label="Permalink to &quot;A2: Separate Repos&quot;">​</a></h3><p><strong>Pros:</strong> Maximum autonomy <strong>Cons:</strong> Version coordination nightmare, harder to ensure determinism across modules <strong>Rejected:</strong> Cross-module determinism requires synchronized ticks</p><h3 id="a3-flat-workspace-no-sub-modules" tabindex="-1">A3: Flat Workspace (No Sub-Modules) <a class="header-anchor" href="#a3-flat-workspace-no-sub-modules" aria-label="Permalink to &quot;A3: Flat Workspace (No Sub-Modules)&quot;">​</a></h3><p><strong>Pros:</strong> Simple structure <strong>Cons:</strong> No boundary enforcement, all crates at same level <strong>Rejected:</strong> Violates dependency ordering (e.g., climate should not depend on geo)</p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><h3 id="crate-structure-template" tabindex="-1">Crate Structure Template <a class="header-anchor" href="#crate-structure-template" aria-label="Permalink to &quot;Crate Structure Template&quot;">​</a></h3><p>Each crate should follow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>crates/{name}/</span></span>
<span class="line"><span>  Cargo.toml</span></span>
<span class="line"><span>  src/</span></span>
<span class="line"><span>    lib.rs         # Public API</span></span>
<span class="line"><span>    module1.rs     # Implementation</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>  tests/</span></span>
<span class="line"><span>    integration_tests.rs</span></span>
<span class="line"><span>  README.md        # Crate-specific docs</span></span></code></pre></div><h3 id="workspace-configuration" tabindex="-1">Workspace Configuration <a class="header-anchor" href="#workspace-configuration" aria-label="Permalink to &quot;Workspace Configuration&quot;">​</a></h3><p><strong>Root Cargo.toml:</strong></p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">workspace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">members = [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;crates/engine&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;crates/economy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;crates/spatial&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... etc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><h3 id="boundary-enforcement" tabindex="-1">Boundary Enforcement <a class="header-anchor" href="#boundary-enforcement" aria-label="Permalink to &quot;Boundary Enforcement&quot;">​</a></h3><p><strong>tach.toml</strong> (via <a href="https://www.notion.so/Tach-Python-42da5cfc6bda4a098e39b88e2a34b86f" target="_blank" rel="noreferrer">Tach</a>):</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">boundaries</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;engine&quot; = []  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># No dependencies</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;economy&quot; = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;engine&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;spatial&quot; = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;engine&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;climate&quot; = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;engine&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;economy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ... full graph</span></span></code></pre></div><p>Run: <code>tach check</code> (pre-commit hook)</p><h2 id="validation-commands" tabindex="-1">Validation Commands <a class="header-anchor" href="#validation-commands" aria-label="Permalink to &quot;Validation Commands&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Build all crates</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Test all crates</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check dependency boundaries</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tach</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Lint</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clippy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all-targets</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> warnings</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Format</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fmt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><strong>CIV-0001:</strong> Core Simulation Loop spec</li><li><strong>CIV-0100–0106:</strong> Domain-specific specs</li><li><strong>CLAUDE.md:</strong> Project governance (cross-module determinism)</li><li><strong>Tach:</strong> Boundary enforcement tool (<a href="https://github.com/gauge-sh/tach" target="_blank" rel="noreferrer">https://github.com/gauge-sh/tach</a>)</li></ul><hr><p><strong>Decision Delta:</strong></p><ul><li>Workspace-based organization with 9 focused crates</li><li>Dependency graph enforced via <code>tach.toml</code></li><li>Single <code>server/</code> crate for Venture integration</li></ul><p><strong>Review Date:</strong> 2026-05-21 (after P0 implementation)</p>`,48)])])}const g=a(t,[["render",l]]);export{u as __pageData,g as default};
